## 3. Building the extension  

Below are three common ways to compile the above file. Choose the one that fits your project.

### 3.1. `setup.py` (classic setuptools)

```python
# -------------------------------------------------
#  setup.py  –  build libpcapng Python extension
# -------------------------------------------------
from setuptools import setup, Extension
import sys, os, pathlib

# pybind11 helper – it ships a small header‑only helper for the include dir
import pybind11
include_dirs = [pybind11.get_include()]

# If your libpcapng is installed system‑wide, you may need to add
# its include directory and link library here.
# e.g. include_dirs.append("/usr/include/libpcapng")
#      library_dirs.append("/usr/lib")
#      libraries.append("pcapng")

ext_modules = [
    Extension(
        "libpcapng",
        ["bindings.cpp"],
        include_dirs=include_dirs,
        language="c++",
        # extra_compile_args=["-std=c++17"],   # adjust if needed
    ),
]

setup(
    name="libpcapng",
    version="0.1.0",
    author="Your Name",
    description="Python bindings for libpcapng",
    ext_modules=ext_modules,
    zip_safe=False,
)
```

**Build & install**

```bash
$ pip install .
# or, for an editable install:
$ pip install -e .
```

### 3.2. `CMakeLists.txt` (modern CMake)

```cmake
cmake_minimum_required(VERSION 3.14)
project(libpcapng_bindings LANGUAGES CXX)

# Find pybind11 (expects it as a submodule or installed package)
find_package(pybind11 REQUIRED)

# -----------------------------------------------------------------
#  Add the libpcapng library – replace with the real target if you have one.
#  If libpcapng is header‑only you can just add its include dir.
# -----------------------------------------------------------------
# add_library(pcapng STATIC ...)   # example
# target_include_directories(pcapng PUBLIC /path/to/pcapng/include)

pybind11_add_module(libpcapng bindings.cpp)

# If you linked against a compiled libpcapng library:
# target_link_libraries(libpcapng PRIVATE pcapng)

# If you need extra include dirs:
# target_include_directories(libpcapng PRIVATE /path/to/pcapng/include)

# Use C++17 (or whatever your lib needs)
target_compile_features(libpcapng PRIVATE cxx_std_17)
```

```bash
mkdir build && cd build
cmake .. -DCMAKE_BUILD_TYPE=Release
cmake --build .
# The resulting `libpcapng.cpython-*.so` can be copied/installed into your site‑packages.
```

### 3.3. `pyproject.toml` (PEP‑517/518, modern build)

```toml
# -------------------------------------------------
#  pyproject.toml  –  build libpcapng with scikit‑build
# -------------------------------------------------
[build-system]
requires = ["setuptools>=42", "wheel", "pybind11>=2.6"]
build-backend = "setuptools.build_meta"

[project]
name = "libpcapng"
version = "0.1.0"
description = "Python bindings for libpcapng"
authors = [{name = "Your Name"}]
requires-python = ">=3.8"

[tool.setuptools]
ext-modules = [
    {name = "libpcapng", sources = ["bindings.cpp"]},
]
```

```bash
$ pip install .
```

All three approaches produce a single shared object named `libpcapng.*.so` that can be imported as `import libpcapng`.

