## 4. Full usage example (Python)

```python
# -------------------------------------------------
#  example.py – demo of the public API
# -------------------------------------------------
from libpcapng import PcapngReader, Frame

def print_summary(frame: Frame) -> None:
    # Show a one‑line summary for each captured packet
    ts = frame.timestamp
    length = frame.length
    # Show only the first 12 bytes (hex) to keep output readable
    payload = frame.data[:12].hex()
    print(f"{ts:0.6f}s  len={length:4d}  payload={payload}")

def main():
    # Replace with a real pcapng file you have.
    pcap_path = "samples/example.pcapng"

    # -----------------------------------------------------------------
    #  1) Callback style – fastest for pure side‑effects
    # -----------------------------------------------------------------
    print("=== Callback style ===")
    with PcapngReader(pcap_path) as rdr:
        rdr.foreach(print_summary)

    # -----------------------------------------------------------------
    #  2) Iterator style – works with any Python loop construct
    # -----------------------------------------------------------------
    print("\n=== Iterator style ===")
    with PcapngReader(pcap_path) as rdr:
        for frame in rdr:
            # You could also do more complex processing here.
            print_summary(frame)

if __name__ == "__main__":
    main()
```

Running `python example.py` will produce something like:

```
